export function authenticateStudent(email: string, password: string): Student | null {
  return STUDENTS.find(s => s.email === email && s.password === password) ?? null
}

export function getStudentsBySection(section: string): Student[] {
  return STUDENTS.filter(s => s.section === section)
}

export function getSections(): string[] {
  return ["I CSE-A", "I CSE-B", "II CSE-A", "II CSE-B", "III CSE-A", "III CSE-B"]
}

export function getTotalStudentCount(): number {
  return STUDENTS.length
}

